import{_ as t,c as i,o as a,ae as l}from"./chunks/framework.CMFi8ROq.js";const V=JSON.parse('{"title":"框架","description":"","frontmatter":{},"headers":[],"relativePath":"interview/框架.md","filePath":"interview/框架.md","lastUpdated":null}'),c={name:"interview/框架.md"};function o(r,e,u,p,n,s){return a(),i("div",null,e[0]||(e[0]=[l('<h1 id="框架" tabindex="-1">框架 <a class="header-anchor" href="#框架" aria-label="Permalink to &quot;框架&quot;">​</a></h1><h2 id="vue-的虚拟-dom-和-react-中的虚拟-dom-有什么区别" tabindex="-1">Vue 的虚拟 DOM 和 React 中的虚拟 DOM 有什么区别? <a class="header-anchor" href="#vue-的虚拟-dom-和-react-中的虚拟-dom-有什么区别" aria-label="Permalink to &quot;Vue 的虚拟 DOM 和 React 中的虚拟 DOM 有什么区别?&quot;">​</a></h2><p>虽然 Vue 和 React 都使用了虚拟 DOM（VDOM）来减少直接操作真实 DOM 的开销，但由于两者的设计哲学不同，它们的 VDOM 在实现机制、Diff 策略以及底层架构上有着本质的区别。</p><p><strong>1. 编译时 vs 运行时 (Aot vs Runtime)</strong></p><p>这是两者产生差异的最根本原因：</p><ul><li><p>Vue (重编译时优化)：Vue 在模板编译阶段做了大量“预处理”。它能静态分析模板，标记出哪些是静态内容（永不改变），哪些是动态绑定。</p><ul><li>Patch Flag（补丁标志）：Vue 3 会在动态节点上打标签（如：这个节点只有 class 会变）。Diff 时，Vue 直接跳过静态节点，只对比带标签的动态节点。</li></ul></li><li><p>React (纯运行时)：React 几乎没有编译时优化。对于 React 来说，JSX 编译后就是单纯的 ReactElement 调用。</p><ul><li>React 不知道哪些是动态的，哪些是静态的，所以每次更新都需要递归遍历整棵 Fiber 树进行全量对比（虽然有 memo，但仍需检查）。</li></ul></li></ul><p><strong>2. Diff 算法的演进与实现</strong></p><ul><li><p>React (Fiber 架构 / 链表遍历)：</p><ul><li>结构：React 将 VDOM 进化为了 Fiber 链表。</li><li>算法：采用单向链表遍历。由于支持时间分片 (Time Slicing)，React 的 Diff 可以被中断，先去处理高优先级任务，再找回指针继续对比。</li><li>特点：牺牲了一定的对比速度，换取了极高的交互响应性。</li></ul></li><li><p>Vue (双端 Diff / 快速 Diff)：</p><ul><li>结构：Vue 的 VDOM 依然是传统的树状结构。</li><li>算法：Vue 2 采用双端 Diff（四个指针向中间靠拢）；Vue 3 采用了借鉴于 ivi 和 inferno 的 快速 Diff (Quick Diff) 算法，利用了最长递增子序列（LIS）来最小化 DOM 移动操作。</li><li>特点：在纯对比速度上，Vue 通常比 React 更快，因为它不需要维护复杂的 Fiber 状态调度。</li></ul></li></ul><p><strong>3. 更新粒度 (Granularity)</strong></p><ul><li><p>Vue (组件级精确更新)：</p><p>Vue 的每个组件都有一个渲染 Watcher。通过响应式系统 (Proxy)，Vue 精确知道是哪个数据变了，从而只触发受影响组件的重新渲染。</p><p>结论：Vue 的 VDOM 更新是“靶向”的，不需要对整个应用树进行大规模对比。</p></li><li><p>React (全量自上而下更新)：</p><p>默认情况下，React 调用 <code>setState</code> 后，会从当前组件开始，递归地重新渲染所有子组件。</p><p>结论：React 依赖于 VDOM 的对比速度和调度策略。开发者通常需要手动使用 <code>useMemo</code> 或 <code>React.memo</code> 来跳过不必要的子树对比。</p></li></ul><p><strong>4. 架构载体 (The Core Carrier)</strong></p><ul><li>React：虚拟 DOM 已经变成了 Fiber 节点。它不仅是 UI 的描述，还是任务调度和状态存储的载体（Hooks 就在 Fiber 上）。</li><li>Vue：虚拟 DOM 主要是 VNode。它更多地作为一个中间层，核心状态存储在响应式对象（Reactive Objects）中，而非 VNode 节点本身。</li></ul><h2 id="在-react-中-为什么修改-state-后组件不会立即重新渲染-而是需要等待事件循环结束-这与-vue-的异步更新队列-nexttick-有何异同" tabindex="-1">在 React 中，为什么修改 state 后组件不会立即重新渲染，而是需要等待事件循环结束？这与 Vue 的异步更新队列（nextTick）有何异同？ <a class="header-anchor" href="#在-react-中-为什么修改-state-后组件不会立即重新渲染-而是需要等待事件循环结束-这与-vue-的异步更新队列-nexttick-有何异同" aria-label="Permalink to &quot;在 React 中，为什么修改 state 后组件不会立即重新渲染，而是需要等待事件循环结束？这与 Vue 的异步更新队列（nextTick）有何异同？&quot;">​</a></h2><p><strong>1. React 为什么不立即更新？</strong></p><p>如果一个函数里连续调用了 3 次 setState，React 如果立即渲染 3 次，会导致巨大的性能开销（因为渲染涉及复杂的 Diff 计算）。</p><ul><li>实现机制：React 会将这些更新任务先放入 Fiber 节点的 <code>updateQueue</code> 中</li><li>结果：在同一个事件循环（Event Loop）的任务里，React 会将它们“合并”，最终只触发一次渲染。</li></ul><p><strong>2.与Vue的nextTick的异同</strong></p><ul><li><p>相同点：</p><ul><li>目的一致：都是为了避免频繁的 DOM 操作，减少渲染次数，提升性能。</li><li>宏观表现：在同一个同步代码块中修改多次数据，最终只会触发一次渲染。</li></ul></li><li><p>不同点：</p><ul><li><p>Vue <code>nextTick</code>的逻辑：</p><p>Vue 像是一个“守门员”。当你修改 data，它只是把这个组件标记为“待刷新”，并塞进一个微任务队列。等你的同步代码全部跑完，微任务启动，它才去一次性刷新 DOM。所以你必须用 nextTick 才能拿到更新后的 DOM。</p></li><li><p>React 的逻辑</p><p>React 18 之后，所有的更新（包括 Promises、setTimeout、原生事件）都是自动批处理的。React 并不只是为了“等 DOM 刷好”，它是在 “权衡优先级”。</p></li></ul></li></ul>',18)]))}const f=t(c,[["render",o]]);export{V as __pageData,f as default};
